import{_ as o,o as t,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"73. Professional Development Leave","description":"","frontmatter":{"title":"73. Professional Development Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["education-pd","leave"]},"headers":[],"relativePath":"ebas/mspp/leave/73-professional-development-leave.md","filePath":"ebas/mspp/leave/73-professional-development-leave.md"}'),s={name:"ebas/mspp/leave/73-professional-development-leave.md"};function i(r,e,l,p,d,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_73-professional-development-leave" tabindex="-1">73. Professional Development Leave <a class="header-anchor" href="#_73-professional-development-leave" aria-label="Permalink to &quot;73. Professional Development Leave&quot;">​</a></h1><p><strong>73.1</strong> Additional Schedules</p><p><strong>a.</strong> Provisions additional to those prescribed by this clause apply at the following Health Services and are contained in 74 and 75 and.</p><p><strong>(i)</strong> <a href="/eba/ebas/mspp/schedules/8-royal-women-s-hospital-royal-children-s-hospital-general-emp.html">Schedule 8</a> Royal Women’s Hospital</p><p><strong>(ii)</strong> <a href="/eba/ebas/mspp/schedules/9-royal-children-s-hospital-clinical-perfusionists.html">Schedule 9</a> Royal Children’s Hospital</p><p><strong>(iii)</strong> <a href="/eba/ebas/mspp/schedules/10-st-vincent-s-health-melbourne-ltd-general-conditions-agreeme.html">Schedule 10</a> St. Vincent’s Health</p><p><strong>b.</strong> Professional Development is the means by which members of a profession maintain, improve and broaden their knowledge and expertise, and develop personal and professional qualities by:</p><p><strong>(i)</strong> reviewing practice; and</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>(ii)</strong> identifying learning needs; and</p><p><strong>(iii)</strong> planning and participating in relevant learning activities; and</p><p><strong>(iv)</strong> reflecting on the value of those activities.</p><p><strong>73.2</strong> Entitlement</p><p><strong>a.</strong> All Employees are entitled to five days&#39; paid Professional Development Leave in addition to other leave entitlements. Part-time Employees are entitled to paid Professional Development Leave on a pro rata basis.</p><p><strong>b.</strong> Where a regular and systematic casual (as described at 70.2 (a)(i)) seeks to undertake professional development that is directly relevant to the work undertaken for the Employer, the Employee may apply for paid Professional Development leave. The Employer will not unreasonably refuse the application.</p><p><strong>c.</strong> An Employee may utilise Professional Development Leave for part of a single day.</p><p><strong>d.</strong> The leave in clause 73.2a is cumulative over two calendar years.</p><p><strong>e.</strong> Professional development leave may be utilised for learning activities including but not limited to research, home study, and attendance at conferences and seminars.</p><p><strong>73.3</strong> Applications</p><p><strong>a.</strong> Applications for Professional Development Leave must be made in writing to the Employer at least six weeks&#39; prior to the proposed leave date, providing that an application made less than six weeks prior to the proposed leave date will still be considered for approval which will not be unreasonably withheld.</p><p><strong>b.</strong> Applications for Professional Development Leave may include paid or unpaid leave.</p><p><strong>c.</strong> Applications for Professional Development Leave may include the period of time in which the Employee is traveling to and from the learning activity.</p><p><strong>d.</strong> An Employee applying to take Professional Development Leave to undertake home study must include details of the relevance of the study to the Employee&#39;s employment in the application.</p><p><strong>e.</strong> The Employer must, within seven days, notify the Employee in writing whether the leave request is approved. If the leave is not granted, the reasons will be included in the notification to the Employee.</p><p><strong>f.</strong> The Employer will not unreasonably withhold approval of the leave.</p><p><strong>g.</strong> Except for the conditions in this clause, no other conditions will be attached to the granting of Professional Development Leave.</p><p><strong>h.</strong> Where an application for Professional Development Leave which is approved by the Employer covers a period where the Employee would be rostered off (e.g. on weekends, ADOs or after hours), the Employer will provide time in lieu for the period of the course.</p><p><strong>i.</strong> For the purposes of clause 73.3h, time in lieu means time for time at ordinary rates and does not include any benefit or payment for any overtime, penalties or allowances under this Agreement which would normally be paid for such periods of duty.</p><p><strong>j.</strong> Any dispute about the reasonableness of withholding of approval of Professional Development Leave shall be dealt with under <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">Clause 11</a> – Dispute Settling Procedure.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p>Plain language terms: PD leave, training leave.</p>',31)])])}const v=o(s,[["render",i]]);export{c as __pageData,v as default};
